import { useState, useEffect, useCallback } from "react";
import { supabase } from "../lib/supabase";

// Generate venue ID from name
function generateVenueId(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9]+/g, '').replace(/^-|-$/g, '');
}

// Convert hex to rgba for background with opacity
function hexToRgba(hex: string, alpha: number): string {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
}

// Venue type matching database schema
interface Venue {
  id: string;
  name: string;
  description: string | null;
  address: string | null;
  city: string;
  state: string;
  website_url: string | null;
  color_hex: string | null;
  active: boolean;
  aliases: string[] | null;
}

// Form state for editing/creating venues
interface VenueForm {
  name: string;
  description: string;
  address: string;
  city: string;
  state: string;
  website_url: string;
  colorHex: string;
  active: boolean;
  aliases: string[];
}

const DEFAULT_FORM: VenueForm = {
  name: "",
  description: "",
  address: "",
  city: "Omaha",
  state: "NE",
  website_url: "",
  colorHex: "#6b7280",
  active: true,
  aliases: [],
};

export function VenueManagement() {
  const [venues, setVenues] = useState<Venue[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [modalOpen, setModalOpen] = useState(false);
  const [editingVenue, setEditingVenue] = useState<Venue | null>(null);
  const [form, setForm] = useState<VenueForm>(DEFAULT_FORM);
  const [saving, setSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Fetch all venues (including inactive)
  const fetchVenues = useCallback(async () => {
    const { data, error } = await supabase
      .from("venues")
      .select("*")
      .order("name");

    if (error) {
      console.error("Failed to fetch venues:", error);
      return;
    }

    setVenues(data || []);
  }, []);

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      await fetchVenues();
      setLoading(false);
    };
    load();
  }, [fetchVenues]);

  // Filter venues by search
  const filteredVenues = venues.filter((venue) => {
    if (!search.trim()) return true;
    const searchLower = search.toLowerCase();
    return (
      venue.name.toLowerCase().includes(searchLower) ||
      venue.id.toLowerCase().includes(searchLower) ||
      venue.address?.toLowerCase().includes(searchLower) ||
      venue.city.toLowerCase().includes(searchLower)
    );
  });

  // Open modal for adding new venue
  const openAddModal = () => {
    setEditingVenue(null);
    setForm(DEFAULT_FORM);
    setError(null);
    setModalOpen(true);
  };

  // Open modal for editing existing venue
  const openEditModal = (venue: Venue) => {
    setEditingVenue(venue);
    setForm({
      name: venue.name,
      description: venue.description || "",
      address: venue.address || "",
      city: venue.city,
      state: venue.state,
      website_url: venue.website_url || "",
      colorHex: venue.color_hex || "#6b7280",
      active: venue.active,
      aliases: venue.aliases || [],
    });
    setError(null);
    setModalOpen(true);
  };

  // Close modal
  const closeModal = () => {
    setModalOpen(false);
    setEditingVenue(null);
    setForm(DEFAULT_FORM);
    setError(null);
  };

  // Update form field
  const updateForm = (field: keyof VenueForm, value: string | boolean | string[]) => {
    setForm((prev) => ({ ...prev, [field]: value }));
  };

  // Save venue (create or update)
  const handleSave = async () => {
    if (!form.name.trim()) {
      setError("Name is required");
      return;
    }

    setSaving(true);
    setError(null);

    // Generate ID from name for new venues
    const venueId = editingVenue ? editingVenue.id : generateVenueId(form.name);

    const venueData = {
      id: venueId,
      name: form.name.trim(),
      description: form.description.trim() || null,
      address: form.address.trim() || null,
      city: form.city.trim(),
      state: form.state.trim(),
      website_url: form.website_url.trim() || null,
      color_hex: form.colorHex,
      active: form.active,
      aliases: form.aliases.length > 0 ? form.aliases : null,
    };

    try {
      if (editingVenue) {
        // Update existing venue
        const { error } = await supabase
          .from("venues")
          .update({
            name: venueData.name,
            description: venueData.description,
            address: venueData.address,
            city: venueData.city,
            state: venueData.state,
            website_url: venueData.website_url,
            color_hex: venueData.color_hex,
            active: venueData.active,
            aliases: venueData.aliases,
          })
          .eq("id", editingVenue.id);

        if (error) throw error;
      } else {
        // Create new venue
        const { error } = await supabase.from("venues").insert(venueData);

        if (error) {
          if (error.code === "23505") {
            throw new Error(`A venue with ID "${venueId}" already exists`);
          }
          throw error;
        }
      }

      await fetchVenues();
      closeModal();
    } catch (err) {
      console.error("Failed to save venue:", err);
      setError(err instanceof Error ? err.message : "Failed to save venue");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div>
      {/* Header */}
      <div className="flex items-center justify-between mb-4">
        <p className="text-gray-500 text-sm">
          {venues.length} venue{venues.length !== 1 ? "s" : ""} total
        </p>
        <button
          onClick={openAddModal}
          className="px-4 py-2 text-sm font-medium bg-gradient-to-r from-amber-500 to-rose-500 text-white rounded-lg hover:from-amber-400 hover:to-rose-400 transition-all"
        >
          + Add Venue
        </button>
      </div>

      {/* Search */}
      <div className="mb-4">
        <div className="relative">
          <svg
            className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500"
            fill="none"
            stroke="currentColor"
            viewBox="0 0 24 24"
          >
            <path
              strokeLinecap="round"
              strokeLinejoin="round"
              strokeWidth={2}
              d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
            />
          </svg>
          <input
            type="text"
            placeholder="Search venues..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-500 focus:outline-none focus:border-gray-500"
          />
        </div>
      </div>

      {loading ? (
        <div className="flex items-center justify-center py-12">
          <div className="w-8 h-8 border-2 border-gray-600 border-t-gray-400 rounded-full animate-spin" />
        </div>
      ) : filteredVenues.length === 0 ? (
        <div className="text-center py-8 text-gray-500">
          {search ? "No venues match your search." : "No venues found."}
        </div>
      ) : (
        <div className="divide-y divide-gray-800">
          {filteredVenues.map((venue) => {
            const hex = venue.color_hex || "#6b7280";
            return (
              <div
                key={venue.id}
                onClick={() => openEditModal(venue)}
                className="flex items-center gap-3 py-3 hover:bg-white/5 cursor-pointer transition-colors -mx-2 px-2"
              >
                {/* Color swatch */}
                <div
                  className="w-4 h-4 rounded-full flex-shrink-0"
                  style={{ backgroundColor: hex }}
                />

                {/* Venue ID badge with color */}
                <span className="text-sm flex-shrink-0 min-w-[100px]" style={{ color: hex }}>
                  {venue.id}
                </span>

                {/* Venue name */}
                <span className="text-white font-medium flex-1 truncate">
                  {venue.name}
                </span>

                {/* Address */}
                <span className="text-gray-500 text-sm truncate max-w-[200px] hidden md:block">
                  {venue.address ? `${venue.address}, ${venue.city}` : venue.city}
                </span>

                {/* Active status */}
                <span className={`text-xs flex-shrink-0 ${venue.active ? "text-green-400" : "text-gray-500"}`}>
                  {venue.active ? "Active" : "Inactive"}
                </span>
              </div>
            );
          })}
        </div>
      )}

      {/* Add/Edit Modal */}
      {modalOpen && (
        <div
          className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80"
          onClick={closeModal}
        >
          <div
            className="w-full max-w-lg max-h-[90vh] bg-gray-900 border border-gray-700 rounded-xl overflow-hidden"
            onClick={(e) => e.stopPropagation()}
          >
            {/* Header */}
            <div className="flex items-center justify-between p-4 border-b border-gray-800">
              <h3 className="text-lg font-semibold text-white">
                {editingVenue ? "Edit Venue" : "Add Venue"}
              </h3>
              <button
                onClick={closeModal}
                className="p-2 text-gray-400 hover:text-white rounded-lg hover:bg-gray-800 transition-colors"
              >
                <svg
                  className="w-5 h-5"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M6 18L18 6M6 6l12 12"
                  />
                </svg>
              </button>
            </div>

            {/* Form */}
            <div className="p-4 overflow-y-auto max-h-[calc(90vh-140px)] space-y-4">
              {/* Error message */}
              {error && (
                <div className="p-3 bg-red-500/20 border border-red-500/50 rounded-lg text-red-400 text-sm">
                  {error}
                </div>
              )}

              {/* Name */}
              <div>
                <label className="block text-sm text-gray-400 mb-1">Name *</label>
                <input
                  type="text"
                  value={form.name}
                  onChange={(e) => updateForm("name", e.target.value)}
                  placeholder="e.g. The Slowdown"
                  className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-600 focus:outline-none focus:border-gray-500"
                />
                {editingVenue && (
                  <p className="text-xs text-gray-500 mt-1">ID: {editingVenue.id}</p>
                )}
              </div>

              {/* Address */}
              <div>
                <label className="block text-sm text-gray-400 mb-1">Address</label>
                <input
                  type="text"
                  value={form.address}
                  onChange={(e) => updateForm("address", e.target.value)}
                  placeholder="e.g. 729 N 14th St"
                  className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-600 focus:outline-none focus:border-gray-500"
                />
              </div>

              {/* City & State */}
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm text-gray-400 mb-1">City</label>
                  <input
                    type="text"
                    value={form.city}
                    onChange={(e) => updateForm("city", e.target.value)}
                    placeholder="Omaha"
                    className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-600 focus:outline-none focus:border-gray-500"
                  />
                </div>
                <div>
                  <label className="block text-sm text-gray-400 mb-1">State</label>
                  <input
                    type="text"
                    value={form.state}
                    onChange={(e) => updateForm("state", e.target.value)}
                    placeholder="NE"
                    className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-600 focus:outline-none focus:border-gray-500"
                  />
                </div>
              </div>

              {/* Website URL */}
              <div>
                <label className="block text-sm text-gray-400 mb-1">Website URL</label>
                <input
                  type="url"
                  value={form.website_url}
                  onChange={(e) => updateForm("website_url", e.target.value)}
                  placeholder="https://example.com"
                  className="w-full px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-600 focus:outline-none focus:border-gray-500"
                />
              </div>

              {/* Aliases */}
              <div>
                <label className="block text-sm text-gray-400 mb-1">
                  Aliases (for venue matching)
                </label>
                <p className="text-xs text-gray-500 mb-2">
                  Alternative names that should match this venue (e.g., "waiting room", "the waiting room")
                </p>

                {/* Current aliases */}
                <div className="flex flex-wrap gap-2 mb-2">
                  {form.aliases.map((alias, index) => (
                    <div
                      key={index}
                      className="flex items-center gap-1 px-2 py-1 bg-gray-800 border border-gray-700 rounded-lg text-sm"
                    >
                      <input
                        type="text"
                        value={alias}
                        onChange={(e) => {
                          const newAliases = [...form.aliases];
                          newAliases[index] = e.target.value;
                          updateForm("aliases", newAliases);
                        }}
                        className="bg-transparent text-white outline-none w-32"
                      />
                      <button
                        type="button"
                        onClick={() => {
                          const newAliases = form.aliases.filter((_, i) => i !== index);
                          updateForm("aliases", newAliases);
                        }}
                        className="text-gray-500 hover:text-red-400 transition-colors"
                      >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                        </svg>
                      </button>
                    </div>
                  ))}
                </div>

                {/* Add new alias */}
                <div className="flex gap-2">
                  <input
                    type="text"
                    placeholder="Add alias..."
                    onKeyDown={(e) => {
                      if (e.key === "Enter" && e.currentTarget.value.trim()) {
                        e.preventDefault();
                        updateForm("aliases", [...form.aliases, e.currentTarget.value.trim().toLowerCase()]);
                        e.currentTarget.value = "";
                      }
                    }}
                    className="flex-1 px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-600 focus:outline-none focus:border-gray-500"
                  />
                  <button
                    type="button"
                    onClick={(e) => {
                      const input = e.currentTarget.previousElementSibling as HTMLInputElement;
                      if (input.value.trim()) {
                        updateForm("aliases", [...form.aliases, input.value.trim().toLowerCase()]);
                        input.value = "";
                      }
                    }}
                    className="px-3 py-2 bg-gray-700 hover:bg-gray-600 text-gray-300 text-sm rounded-lg transition-colors"
                  >
                    + Add
                  </button>
                </div>
              </div>

              {/* Color */}
              <div>
                <label className="block text-sm text-gray-400 mb-1">Color</label>
                <div className="flex gap-2 items-center">
                  <input
                    type="color"
                    value={form.colorHex}
                    onChange={(e) => updateForm("colorHex", e.target.value)}
                    className="w-12 h-10 bg-gray-800 border border-gray-700 rounded-lg cursor-pointer"
                  />
                  <input
                    type="text"
                    value={form.colorHex}
                    onChange={(e) => updateForm("colorHex", e.target.value)}
                    placeholder="#6b7280"
                    className="flex-1 px-3 py-2 bg-gray-800 border border-gray-700 rounded-lg text-white placeholder-gray-600 focus:outline-none focus:border-gray-500 font-mono"
                  />
                </div>
                {/* Preview */}
                <div className="mt-2 flex items-center gap-2">
                  <span className="text-xs text-gray-500">Preview:</span>
                  <span
                    className="text-xs px-2 py-0.5 rounded border"
                    style={{
                      backgroundColor: hexToRgba(form.colorHex, 0.2),
                      color: form.colorHex,
                      borderColor: form.colorHex,
                    }}
                  >
                    {editingVenue?.id || generateVenueId(form.name) || "venue-id"}
                  </span>
                </div>
              </div>

              {/* Active Toggle */}
              <div className="flex items-center justify-between py-2">
                <div>
                  <label className="block text-sm text-white">Active</label>
                  <p className="text-xs text-gray-500">
                    Inactive venues are hidden from public view
                  </p>
                </div>
                <button
                  type="button"
                  onClick={() => updateForm("active", !form.active)}
                  className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                    form.active ? "bg-green-500" : "bg-gray-600"
                  }`}
                >
                  <span
                    className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                      form.active ? "translate-x-6" : "translate-x-1"
                    }`}
                  />
                </button>
              </div>
            </div>

            {/* Footer */}
            <div className="flex items-center justify-end gap-2 p-4 border-t border-gray-800">
              <button
                onClick={closeModal}
                className="px-4 py-2 text-sm text-gray-400 hover:text-white border border-gray-700 rounded-lg hover:border-gray-500 transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleSave}
                disabled={saving}
                className="px-4 py-2 text-sm bg-gray-700 hover:bg-gray-600 text-white rounded-lg disabled:opacity-50 transition-colors"
              >
                {saving ? "Saving..." : editingVenue ? "Save Changes" : "Create Venue"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
